/* ============================================================
 * push-sw.js — Web Push handlers for the SampleHub PWA
 * ============================================================
 * This script is NOT a standalone service worker. It is pulled
 * into the Workbox service worker generated by vite-plugin-pwa
 * via `workbox.importScripts: ['push-sw.js']` (see vite.config.ts).
 *
 * It owns two responsibilities:
 *   - `push`            → show the system notification
 *   - `notificationclick` → focus/open the app at the request
 *
 * The payload is sent by the `send-request-push` edge function:
 *   { title, body, url, tag }
 * ============================================================ */

self.addEventListener('push', (event) => {
  /** @type {{ title?: string, body?: string, url?: string, tag?: string }} */
  let data = {};
  try {
    data = event.data ? event.data.json() : {};
  } catch (_err) {
    // Fall back to plain text if the payload is not JSON.
    data = { body: event.data ? event.data.text() : '' };
  }

  const title = data.title || 'New Sample Request';
  const options = {
    body: data.body || 'A new request is awaiting your review.',
    icon: '/pwa-192x192.png',
    badge: '/favicon.ico',
    // `tag` collapses duplicate notifications for the same request.
    tag: data.tag || 'sample-request',
    // Carry the deep-link target through to the click handler.
    data: { url: data.url || '/' },
    requireInteraction: false,
  };

  event.waitUntil(self.registration.showNotification(title, options));
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  const targetUrl =
    (event.notification.data && event.notification.data.url) || '/';

  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((clientList) => {
        // If an app window is already open, reuse and navigate it.
        for (const client of clientList) {
          if ('focus' in client) {
            if ('navigate' in client) client.navigate(targetUrl);
            return client.focus();
          }
        }
        // Otherwise open a fresh window at the target route.
        if (self.clients.openWindow) {
          return self.clients.openWindow(targetUrl);
        }
        return undefined;
      })
  );
});
